 4	import { ErrorMsg } from '../../types/ErrorMsg';
 5	
 6	interface MessageProps {
 7	  error: ErrorMsg;
 8	}
 9	
10	const errorSectionStyle = kialiStyle({
11	  height: '80vh'
12	});
13	
14	export const ErrorSection: React.FC<MessageProps> = (props: MessageProps) => {
15	  return (
16	    <div>
17	      <EmptyState id="empty-page-error" variant={EmptyStateVariant.lg} className={errorSectionStyle}>
18	        <EmptyStateHeader titleText={<>{props.error.title}</>} headingLevel="h5" />
